export type BackendApiRouteId = typeof backendApiRoutes[number]['id']
export type FacturadorApiRouteId = typeof facturadorApiRoutes[number]['id']

const backendRouteById = new Map<string, { path: string }>(backendApiRoutes.map((route) => [route.id, route]))

export function buildApiRoute(id: BackendApiRouteId, params: Record<string, string | number> = {}): string {
  const route = backendRouteById.get(id)
  if (!route) {
    throw new Error(`Ruta API no registrada: ${id}`)
  }

  let resolved = route.path
  for (const [key, value] of Object.entries(params)) {
    resolved = resolved.replace(new RegExp(`\\{${key}\\}`, 'g'), encodeURIComponent(String(value)))
  }

  if (/\{[a-zA-Z0-9_]+\}/.test(resolved)) {
    throw new Error(`Faltan parametros para ruta API: ${id}`)
  }

  return resolved
}
